import { useState, useEffect } from 'react';
import { getMyProducts, createProduct, updateProduct, deleteProduct } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

const SellerDashboard = () => {
  const [products, setProducts] = useState([]);
  const [tab, setTab] = useState('products');
  const [form, setForm] = useState({ name: '', description: '', price: '', discountPrice: '', category: '', stock: '', brand: '' });
  const [editId, setEditId] = useState(null);
  const { user } = useAuth();

  const load = () => getMyProducts().then(r => setProducts(r.data.products));
  useEffect(() => { load(); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editId) { await updateProduct(editId, form); toast.success('Product updated!'); }
      else { await createProduct(form); toast.success('Product submitted for approval!'); }
      setForm({ name: '', description: '', price: '', discountPrice: '', category: '', stock: '', brand: '' });
      setEditId(null); setTab('products'); load();
    } catch (err) { toast.error(err.response?.data?.message || 'Error'); }
  };

  const handleEdit = (p) => { setForm({ name: p.name, description: p.description, price: p.price, discountPrice: p.discountPrice || '', category: p.category, stock: p.stock, brand: p.brand || '' }); setEditId(p._id); setTab('add'); };
  const handleDelete = async (id) => { if (window.confirm('Delete?')) { await deleteProduct(id); load(); toast.success('Deleted!'); } };

  return (
    <div className="admin-page">
      <h1>Seller Dashboard</h1>
      <div className="admin-tabs">
        <button className={tab === 'products' ? 'active' : ''} onClick={() => setTab('products')}>My Products</button>
        <button className={tab === 'add' ? 'active' : ''} onClick={() => { setTab('add'); setEditId(null); setForm({ name: '', description: '', price: '', discountPrice: '', category: '', stock: '', brand: '' }); }}>+ Add Product</button>
      </div>

      {tab === 'products' && (
        <table className="admin-table">
          <thead><tr><th>Name</th><th>Price</th><th>Stock</th><th>Status</th><th>Actions</th></tr></thead>
          <tbody>{products.map(p => (
            <tr key={p._id}>
              <td>{p.name}</td><td>PKR {p.price}</td><td>{p.stock}</td>
              <td><span className={p.isApproved ? 'badge-green' : 'badge-yellow'}>{p.isApproved ? 'Approved' : 'Pending'}</span></td>
              <td>
                <button className="btn-sm" onClick={() => handleEdit(p)}>Edit</button>
                <button className="btn-sm btn-danger" onClick={() => handleDelete(p._id)}>Delete</button>
              </td>
            </tr>
          ))}</tbody>
        </table>
      )}

      {tab === 'add' && (
        <form className="product-form" onSubmit={handleSubmit}>
          <h2>{editId ? 'Edit Product' : 'Add New Product'}</h2>
          {['name', 'brand', 'category'].map(f => <input key={f} placeholder={f.charAt(0).toUpperCase() + f.slice(1)} value={form[f]} onChange={e => setForm(p => ({ ...p, [f]: e.target.value }))} required={f !== 'brand'} />)}
          <textarea placeholder="Description" value={form.description} onChange={e => setForm(p => ({ ...p, description: e.target.value }))} required />
          <div className="form-row">
            <input type="number" placeholder="Price (PKR)" value={form.price} onChange={e => setForm(p => ({ ...p, price: e.target.value }))} required />
            <input type="number" placeholder="Discount Price (optional)" value={form.discountPrice} onChange={e => setForm(p => ({ ...p, discountPrice: e.target.value }))} />
            <input type="number" placeholder="Stock" value={form.stock} onChange={e => setForm(p => ({ ...p, stock: e.target.value }))} required />
          </div>
          <button className="btn-primary" type="submit">{editId ? 'Update Product' : 'Submit for Approval'}</button>
          <button className="btn-ghost" type="button" onClick={() => setTab('products')}>Cancel</button>
        </form>
      )}
    </div>
  );
};

export default SellerDashboard;
